import React from "react";
import Typewriter from 'typewriter-effect';

import SlideButton from "../components/SlideButton";

import '../styles/Home.css';


const Home = React.forwardRef((props, ref) => (
    <div ref={ref} className="homePage" id="home" >
        <div className="homeContainerTop">
            <div className="hiText">
                Hi there<span className="redComa">,</span><br />
                My Name is <span className="redName">Charles</span><br />
                <div className="typewritterOff">And I make&nbsp;<span class="webApp">Websites</span></div>
                <div className="typewritter">And I make&nbsp;<Typewriter
                    options={{
                        autoStart: true,
                        loop: true,
                        delay: 50,
                    }}
                    onInit={(typewriter) => {
                        typewriter
                            .typeString('<span class="webApp">Websites</span>')
                            .pauseFor(1500)
                            .deleteAll()
                            .typeString('<span class="webApp">Applications</span>')
                            .pauseFor(1500)
                            .deleteAll()
                            .start();
                    }}
                />
                </div>
            </div>
        </div>
        <div className="homeContainerBottom">
            <SlideButton title="See more about me" to="about" />
        </div>
    </div >
));

export default Home;
